class Comment < ApplicationRecord
  belongs_to :user
  belongs_to :story,
    inverse_of: :comments,
    touch: true
  # has_one :comment_stat, -> { where("date(created_at)",  }
  has_many :votes,
    dependent: :delete_all
  belongs_to :parent_comment,
    class_name: "Comment",
    inverse_of: false,
    optional: true,
    counter_cache: :reply_count,
    touch: true
  has_one :moderation,
    class_name: "Moderation",
    inverse_of: :comment,
    dependent: :restrict_with_exception
  belongs_to :hat,
    optional: true
  has_many :taggings, through: :story
  has_many :links, inverse_of: :from_comment, dependent: :restrict_with_exception
  has_many :incoming_links,
    class_name: "Link",
    inverse_of: :to_comment,
    dependent: :restrict_with_exception
  has_many :notifications, as: :notifiable

  include Token

  attr_accessor :current_vote, :current_reply, :previewing, :vote_summary

  validates :short_id, presence: true, uniqueness: {case_sensitive: false}

  before_validation :assign_initial_attributes, on: :create

  # We log hats before the transaction ends so we can accurately check whether the model changed
  after_save :log_hat_use
  # Calling :record_initial_upvote from after_commit instead of after_create minimizes how many
  # queries happen inside the transaction, which seems to be the cause of bug #1238.
  after_commit :mark_submitter, :record_initial_upvote, on: :create
  after_commit :recreate_links, :update_associated_caches

  scope :deleted, -> { where(is_deleted: true) }
  scope :not_deleted, -> { where(is_deleted: false) }
  scope :not_moderated, -> { where(is_moderated: false) }
  scope :active, -> { not_deleted.not_moderated }
  # Only use accessible_to_user in views that render comments in the flat style. The optimizations
  # in comments/_threads fail if there's a gap in depth. This could be fixed, but the visual display
  # would still be misleading, in A -> B -> C if B is deleted it looks like C is replying directly
  # to A. We have to render the 'comment was deleted' placeholder.
  scope :accessible_to_user, ->(user) { (user && user.is_moderator?) ? all : active }
  scope :recent, -> { where(created_at: (6.months.ago..)) }
  scope :above_average, -> {
    joins(:story)
      .joins("left outer join comment_stats on date(comments.created_at) = comment_stats.date")
      .where("comments.score > coalesce(comment_stats.`average`, 3)")
  }
  scope :on_stories_not_authored_by, ->(user) {
    joins(:story)
      .merge(Story.where.not(user: user, user_is_author: true)) # TODO: authorship/beneficial idea
  }
  scope :for_presentation, -> {
    includes(:user, :hat, moderation: :moderator, story: :user, votes: :user)
  }
  scope :filter_tags, ->(tags) {
    tags.empty? ? all : joins(:story).where(
      Story.arel_table[:id].not_in(
        Tagging.where(tag_id: tags).select(:story_id).arel
      )
    )
  }
  scope :filter_tags_for, ->(user) {
    user.nil? ? all : joins(:story).where(
      Story.arel_table[:id].not_in(
        Tagging.joins(tag: :tag_filters)
          .where(tag_filters: {user_id: user})
          .select(:story_id).arel
      )
    )
  }
  scope :not_on_story_hidden_by, ->(user) {
    user ? where.not(
      HiddenStory.select("TRUE")
      .where(Arel.sql("hidden_stories.story_id = stories.id"))
      .by(user).arel.exists
    ) : where("true")
  }
